            if (i + 1 < glob.Length && glob[i + 1] == '*')
            {
                i += 2;
                if (i < glob.Length && glob[i] == '/')
                    i++;
                result.Append("(.*/)?");
            }
            else
            {
                result.Append("[^/]*");
                i++;
            }
        }
        else if (c == '?')
        {
            result.Append("[^/]");
            i++;
        }
        else if (c == '.')
        {
            result.Append("\\.");
            i++;
