// =============================================================================
public class GlobPatternTests
{
    [Fact]
    public void StarDotExtension_MatchesFileWithExtension()
    {
        // *.test.* should match "foo.test.cs"
        var rules = new List<LabelRule>
        {
            new("*.test.*", "tests", Priority: 1)
        };
