        };
        var changedFiles = new List<string> { "src/AB.cs" };

        var labels = LabelAssigner.AssignLabels(changedFiles, rules);

        Assert.Empty(labels);
    }

    [Fact]
    public void DoubleStarGlob_MatchesAnyTestFile()
    {
