        {
            new("*.md", "markdown", Priority: 1)
        };
        var changedFiles = new List<string> { "README.md" };

        var labels = LabelAssigner.AssignLabels(changedFiles, rules);

        Assert.Contains("markdown", labels);
    }

    [Fact]
