110→static IReadOnlySet<string> AssignLabels(
111→    IEnumerable<string> changedFiles,
112→    IEnumerable<LabelRule> rules)
113→{
114→    if (changedFiles is null) throw new ArgumentNullException(nameof(changedFiles));
115→    if (rules is null) throw new ArgumentNullException(nameof(rules));
116→
117→    var ruleList = rules.ToList();
118→    var labels = new SortedSet<string>(StringComparer.OrdinalIgnoreCase);
119→
120→    foreach (var file in changedFiles)
121→    {
122→        if (string.IsNullOrWhiteSpace(file)) continue;
123→        var normalizedFile = file.Replace('\\', '/');
124→
125→        foreach (var rule in ruleList)
126→        {
127→            if (GlobMatches(normalizedFile, rule.GlobPattern))
128→                labels.Add(rule.Label);
129→        }
130→    }
131→
132→    return labels;
133→}
