135→static IReadOnlySet<string> AssignLabelsWithPriority(
136→    IEnumerable<string> changedFiles,
137→    IEnumerable<LabelRule> rules,
138→    IEnumerable<IReadOnlySet<string>>? conflictGroups = null)
139→{
140→    if (changedFiles is null) throw new ArgumentNullException(nameof(changedFiles));
141→    if (rules is null) throw new ArgumentNullException(nameof(rules));
142→
143→    var ruleList = rules.ToList();
144→    var groups = conflictGroups?.ToList() ?? new List<IReadOnlySet<string>>();
145→    var labelPriorities = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
146→
147→    foreach (var file in changedFiles)
148→    {
149→        if (string.IsNullOrWhiteSpace(file)) continue;
150→        var normalizedFile = file.Replace('\\', '/');
151→
152→        foreach (var rule in ruleList)
153→        {
154→            if (GlobMatches(normalizedFile, rule.GlobPattern))
155→            {
156→                if (!labelPriorities.TryGetValue(rule.Label, out var existing) ||
157→                    rule.Priority < existing)
158→                {
159→                    labelPriorities[rule.Label] = rule.Priority;
160→                }
161→            }
162→        }
163→    }
164→
165→    var result = new SortedSet<string>(StringComparer.OrdinalIgnoreCase);
166→    var handledLabels = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
167→
168→    foreach (var group in groups)
169→    {
170→        string? bestLabel = null;
171→        int bestPriority = int.MaxValue;
172→
173→        foreach (var label in group)
174→        {
175→            if (labelPriorities.TryGetValue(label, out var priority) && priority < bestPriority)
176→            {
177→                bestPriority = priority;
178→                bestLabel = label;
179→            }
180→        }
181→
182→        if (bestLabel is not null)
183→            result.Add(bestLabel);
184→
185→        foreach (var label in group)
186→            handledLabels.Add(label);
187→    }
188→
189→    foreach (var kvp in labelPriorities)
190→    {
191→        if (!handledLabels.Contains(kvp.Key))
192→            result.Add(kvp.Key);
193→    }
194→
195→    return result;
196→}
