198→static bool GlobMatches(string filePath, string pattern)
199→{
200→    var regex = GlobToRegex(pattern);
201→    return Regex.IsMatch(filePath, regex, RegexOptions.IgnoreCase);
202→}
203→
204→static string GlobToRegex(string glob)
205→{
206→    var result = new System.Text.StringBuilder("^");
207→    int i = 0;
208→
209→    while (i < glob.Length)
210→    {
211→        char c = glob[i];
212→
213→        if (c == '*')
214→        {
215→            if (i + 1 < glob.Length && glob[i + 1] == '*')
216→            {
217→                i += 2;
218→                if (i >= glob.Length)
219→                {
220→                    // ** at end of pattern: match anything remaining
221→                    result.Append(".*");
222→                }
223→                else if (glob[i] == '/')
224→                {
225→                    // **/ in middle: match zero or more directory segments
226→                    i++;
227→                    result.Append("(.*/)?");
228→                }
229→                else
230→                {
231→                    result.Append(".*");
232→                }
233→            }
234→            else
235→            {
236→                result.Append("[^/]*");
237→                i++;
238→            }
239→        }
240→        else if (c == '?')
241→        {
242→            result.Append("[^/]");
243→            i++;
244→        }
245→        else if (c == '.')
246→        {
247→            result.Append("\\.");
248→            i++;
249→        }
250→        else if (c == '{')
251→        {
252→            result.Append('(');
253→            i++;
254→        }
255→        else if (c == '}')
256→        {
257→            result.Append(')');
258→            i++;
259→        }
260→        else if (c == ',')
261→        {
262→            result.Append('|');
263→            i++;
264→        }
265→        else
266→        {
267→            result.Append(c);
268→            i++;
269→        }
270→    }
271→
272→    result.Append('$');
273→    return result.ToString();
274→}
